package main

import "fmt"

func main() {
	var m, n int
	fmt.Scan(&m)
	numeros := make([]int, m)
	// le os numeros
	for i := range m {
		fmt.Scan(&numeros[i])
	}

	fmt.Scan(&n)
	apaga := make([]int, n)

	for i := range n {
		fmt.Scan(&apaga[i])
	}

	fmt.Println(numeros)
	fmt.Println(apaga)

}
